    _purchaseStreamSubscription =
        _inAppPurchase.purchaseStream.listen((purchaseDetailsList) {
      _listenToPurchaseUpdates(purchaseDetailsList);
    }, onDone: () {
      _purchaseStreamSubscription.cancel();
