  }) {
    Stripe.publishableKey = publishableKey;
    Stripe.instance.applySettings();
  }

  /// Creates a PaymentIntent on your backend.
  /// This is crucial for PCI compliance as sensitive transaction logic
  /// should reside on your server.
  Future<Map<String, dynamic>> _createPaymentIntent(
      String amount, String currency) async {
    try {
      final response = await http.post(
        Uri.parse('$backendUrl/create-payment-intent'),
        headers: <String, String>{
          'Content-Type': 'application/json; charset=UTF-8',
        },
        body: jsonEncode(<String, String>{
          'amount': amount,
          'currency': currency,
        }),
      );
      if (response.statusCode == 200) {
        return jsonDecode(response.body);
      } else {
        throw Exception(
            'Failed to create PaymentIntent: ${response.statusCode} ${response.body}');
      }
    } catch (e) {
      throw Exception('Error creating PaymentIntent: $e');
    }
  }

